function sel1()		
		{
			if (Ctrl('chkDatosReferenciales').GetCValue() =="0")
			{

				Ctrl('chkDatosReferenciales').SetCValue(1);
				Ctrl('chkDocumentos').SetCValue(1);
				Ctrl('chkDomicilios').SetCValue(1);
				Ctrl('chkEstudios').SetCValue(1);
				Ctrl('chkIdiomas').SetCValue(1);
				Ctrl('chkCursos').SetCValue(1);
				Ctrl('chkCompetencias').SetCValue(1);
				Ctrl('chkAntecedentesLab').SetCValue(1);
				Ctrl('chkDatosFam').SetCValue(1);
			}else
			{				
				Ctrl('chkDatosReferenciales').SetCValue(0);
				Ctrl('chkDocumentos').SetCValue(0);
				Ctrl('chkDomicilios').SetCValue(0);
				Ctrl('chkEstudios').SetCValue(0);
				Ctrl('chkIdiomas').SetCValue(0);
				Ctrl('chkCursos').SetCValue(0);
				Ctrl('chkCompetencias').SetCValue(0);
				Ctrl('chkAntecedentesLab').SetCValue(0);
				Ctrl('chkDatosFam').SetCValue(0);
			}			
		}

		function sel2()		
