		function sel3()		
		{
			if (Ctrl('GP').GetCValue() =="0")
			{			
				Ctrl('chkDatosPuestosPostularia').SetCValue(1);
				Ctrl('chkReferenciasIncripto').SetCValue(1);
				Ctrl('chkDatosReclutamiento').SetCValue(1);
				Ctrl('chkExamenes').SetCValue(1);
				Ctrl('chkEntrevistas').SetCValue(1);
				Ctrl('chkOfertas').SetCValue(1);
